import {
  forwardRef,
  useEffect,
  useRef,
  useState,
  type HTMLAttributes,
  type ReactNode,
} from "react";
import { clsx } from "clsx";
import * as styles from "./CTAGroup.css";
import {
  CTA_GROUP_ORIENTATION_CLASSES,
  type CTAGroupLayout,
  CTAGroupOrientationClass,
  DEFAULT_CTA_GROUP_LAYOUT,
} from "./CTAGroup.config";
import { calculateMinHorizontalWidth } from "./utils";
import { CTAGroupSection } from "./components/CTAGroupSection";

// Re-export subcomponent types
export type { CTAGroupSectionProps } from "./components/CTAGroupSection";

// ============================================================================
// CTAGroup (Main Component)
// ============================================================================

interface CTAGroupCustomProps {
  /**
   * The content of the group (typically buttons)
   */
  children: ReactNode;
  /**
   * Controls the layout direction of the group content.
   * - `auto`: Automatically switches between vertical and horizontal based on
   *   available space and content width.
   * - `vertical`: Children are laid out in a column.
   * - `horizontal`: Children are laid out in a row, positioned at the end.
   * @default 'auto'
   */
  layout?: CTAGroupLayout;
}

export interface CTAGroupProps
  extends
    Omit<HTMLAttributes<HTMLDivElement>, keyof CTAGroupCustomProps>,
    CTAGroupCustomProps {}

const CTAGroupRoot = forwardRef<HTMLDivElement, CTAGroupProps>(
  (
    { children, className, layout = DEFAULT_CTA_GROUP_LAYOUT, ...props },
    ref
  ) => {
    const internalRef = useRef<HTMLDivElement | null>(null);

    const [autoOrientationClass, setAutoOrientationClass] =
      useState<CTAGroupOrientationClass>(
        CTA_GROUP_ORIENTATION_CLASSES.vertical
      );

    const orientationClass =
      layout === "auto"
        ? autoOrientationClass
        : CTA_GROUP_ORIENTATION_CLASSES[layout];

    useEffect(() => {
      // If layout is not auto we don't need to update the autoOrientationClass and can bail early
      if (layout !== "auto") return;

      const element = internalRef.current;
      if (!element) return;

      const updateAutoOrientation = () => {
        // Use the element's own width (respects parent's padding)
        // rather than container.offsetWidth (includes parent's padding)
        const availableWidth = element.offsetWidth;
        const minHorizontalWidth = calculateMinHorizontalWidth(element);
        const orientation =
          availableWidth >= minHorizontalWidth ? "horizontal" : "vertical";
        setAutoOrientationClass(CTA_GROUP_ORIENTATION_CLASSES[orientation]);
      };

      updateAutoOrientation();

      // Watch for element size changes
      const resizeObserver = new ResizeObserver(updateAutoOrientation);
      resizeObserver.observe(element);

      // Watch for content changes (text updates, elements added/removed)
      const mutationObserver = new MutationObserver(updateAutoOrientation);
      mutationObserver.observe(element, {
        childList: true,
        subtree: true,
        characterData: true,
      });

      return () => {
        resizeObserver.disconnect();
        mutationObserver.disconnect();
      };
    }, [layout]);

    return (
      <div
        ref={(node) => {
          internalRef.current = node;
          if (typeof ref === "function") {
            ref(node);
          } else if (ref) {
            ref.current = node;
          }
        }}
        className={clsx(
          styles.ctaGroup({ layout }),
          className,
          orientationClass
        )}
        {...props}
      >
        {children}
      </div>
    );
  }
);

CTAGroupRoot.displayName = "CTAGroup";

// ============================================================================
// Compound Component Export
// ============================================================================

export const CTAGroup = Object.assign(CTAGroupRoot, {
  Section: CTAGroupSection,
});
