import { forwardRef, type HTMLAttributes, type ReactNode } from "react";
import { clsx } from "clsx";
import {
  DEFAULT_CTA_GROUP_SECTION_LAYOUT,
  type CTAGroupSectionLayout,
} from "./CTAGroupSection.config";
import * as styles from "./CTAGroupSection.css";

interface CTAGroupSectionCustomProps {
  /**
   * The content of the section (typically related buttons or links).
   * Use sections to group items that should stay together and be positioned
   * on opposite ends in horizontal layout.
   */
  children: ReactNode;

  /**
   * The layout of the section.
   * - `default`: Items stack vertically in vertical orientation, row in horizontal.
   * - `compact`: Items display in a 2-column grid when in vertical orientation.
   * @default 'default'
   */
  layout?: CTAGroupSectionLayout;
}

export interface CTAGroupSectionProps
  extends
    Omit<HTMLAttributes<HTMLDivElement>, keyof CTAGroupSectionCustomProps>,
    CTAGroupSectionCustomProps {}

export const CTAGroupSection = forwardRef<HTMLDivElement, CTAGroupSectionProps>(
  (
    {
      children,
      className,
      layout = DEFAULT_CTA_GROUP_SECTION_LAYOUT,
      ...props
    },
    ref
  ) => {
    return (
      <div
        ref={ref}
        className={clsx(styles.section({ layout }), className)}
        {...props}
      >
        {children}
      </div>
    );
  }
);

CTAGroupSection.displayName = "CTAGroup.Section";
